import React, { useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import { BottomNav } from './Home';

export default function MyTasks() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    if (!user) { navigate('/signin'); return; }
    api.get('/tasks/my')
      .then(res => setTasks(res.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [user]);

  const filtered = filter === 'all' ? tasks : tasks.filter(t => t.status === filter);

  return (
    <div className="app-container">
      <div className="page-header">
        <span className="page-title" style={{ marginRight: 0 }}>Мои задачи</span>
      </div>

      {/* Filter tabs */}
      <div style={{
        display: 'flex', gap: 8, padding: '12px 16px',
        background: 'white', borderBottom: '1px solid var(--border)',
        overflowX: 'auto'
      }}>
        {['all', 'open', 'in_progress', 'completed'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              padding: '6px 14px', borderRadius: 20, border: 'none', fontWeight: 600,
              fontSize: 13, whiteSpace: 'nowrap', cursor: 'pointer',
              background: filter === f ? 'var(--green)' : 'var(--border)',
              color: filter === f ? 'white' : 'var(--text-muted)',
              transition: 'all 0.15s'
            }}
          >
            {f === 'all' ? 'Все' : f === 'open' ? 'Открытые' : f === 'in_progress' ? 'В работе' : 'Завершённые'}
          </button>
        ))}
      </div>

      <div style={{ padding: '16px 16px 100px' }}>
        {loading && <div className="loading"><div className="spinner" /></div>}

        {!loading && filtered.length === 0 && (
          <div style={{ textAlign: 'center', padding: '48px 20px' }}>
            <div style={{ fontSize: 48, marginBottom: 12 }}>📭</div>
            <div style={{ color: 'var(--text-muted)', fontSize: 15, marginBottom: 20 }}>
              У вас нет задач в этой категории
            </div>
            <button className="btn-primary" style={{ maxWidth: 200 }} onClick={() => navigate('/create-task')}>
              Создать задачу
            </button>
          </div>
        )}

        {filtered.map(task => (
          <Link
            key={task.id}
            to={task.status === 'in_progress' ? `/tasks/${task.id}/status` : `/tasks/${task.id}`}
            style={{ display: 'block', marginBottom: 12 }}
          >
            <div className="card" style={{ borderLeft: `4px solid ${
              task.status === 'open' ? '#16a34a' :
              task.status === 'in_progress' ? '#d97706' : '#0284c7'
            }` }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
                <span style={{ fontWeight: 700, fontSize: 16, flex: 1, marginRight: 8 }}>{task.title}</span>
                <span className={`badge badge-${task.status}`}>
                  {task.status === 'open' ? 'Открыта' : task.status === 'in_progress' ? 'В работе' : '✅'}
                </span>
              </div>

              {task.description && (
                <p style={{ color: 'var(--text-muted)', fontSize: 13, marginBottom: 8, lineHeight: 1.4 }}>
                  {task.description.slice(0, 80)}{task.description.length > 80 ? '...' : ''}
                </p>
              )}

              <div style={{ display: 'flex', gap: 12, fontSize: 12, color: 'var(--text-muted)' }}>
                {task.category && <span>{task.category}</span>}
                {task.payment && <span style={{ color: 'var(--green)', fontWeight: 600 }}>💰 {task.payment} ₸</span>}
                {task.helper_name && (
                  <span>👤 {task.helper_name}</span>
                )}
              </div>
            </div>
          </Link>
        ))}
      </div>

      <BottomNav />
    </div>
  );
}
